class Solution:
    def insert(self, word: str) -> None:
        node = self.root
        for char in word:
            if char not in node.children:
                node.children[char] = Node(char)
            node = node.children[char]

class Node:
    def __init__(self, char):
        self.char = char
        self.children = {}

    def __contains__(self, char):
        return char in self.children


